; 湿地帯

name = モイーズ湿地帯・果樹園
insideName = Orchard
lower = モイーズ湿地帯・地下
level = 15
bgm = forest
isOutdoor = true
shadow = dark
sky = cloudy
outfield = soil
blank = rock

; 画像パーツ
━ = soil
　 = soil
☒ = soil
⏃ = woods
〰 = pond
⑴ = bulletin

; 敵情報
maxGroups = 2
monsters = 猛毒ヘビ,猛毒ぐも,殺人バチ,ピクシー
traps = 石つぶて,毒針,毒ガス,しびれ針,爆弾,魔力吸収,酸スプレー,スモーク

; 移動ポイント
(A) = map:パワーの森, x:13, y:0, way:n, symbol:movev, ask:Go to the next map?
(B) = map:モイーズ湿地帯・西の沼地, x:13 ,y:19, way:s, symbol:movev, ask:Go to the next map?

